import type { CSSProperties, ReactNode } from 'react';
import { Toaster as SonnerToaster, toast } from 'sonner';
import { Info, CheckCircle2, XCircle, AlertTriangle, X } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  Toast                                                                     */
/*  Notification toasts with variants and accent bars.                        */
/*  Wraps Sonner in unstyled mode — uses --ts-toast-* tokens.                 */
/* -------------------------------------------------------------------------- */

/* ----- Variant config ---------------------------------------------------- */

type ToastVariant = 'default' | 'success' | 'error' | 'warning' | 'info';

interface VariantConfig {
  accentColor: string;
  icon: ReactNode;
}

const VARIANT_CONFIG: Record<Exclude<ToastVariant, 'default'>, VariantConfig> = {
  success: {
    accentColor: 'var(--ts-toast-success-accent)',
    icon: <CheckCircle2 size={18} />,
  },
  error: {
    accentColor: 'var(--ts-toast-error-accent)',
    icon: <XCircle size={18} />,
  },
  warning: {
    accentColor: 'var(--ts-toast-warning-accent)',
    icon: <AlertTriangle size={18} />,
  },
  info: {
    accentColor: 'var(--ts-toast-info-accent)',
    icon: <Info size={18} />,
  },
};

/* ----- Styles ------------------------------------------------------------ */

const toastBaseStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'flex-start',
  gap: '12px',
  background: 'var(--ts-toast-bg)',
  border: '1px solid var(--ts-toast-border)',
  borderRadius: 'var(--ts-toast-radius)',
  boxShadow: 'var(--ts-toast-shadow)',
  padding: 'var(--ts-toast-padding)',
  color: 'var(--ts-toast-text)',
  fontFamily: 'inherit',
  fontSize: 'var(--ts-font-md)',
  position: 'relative',
  overflow: 'hidden',
  boxSizing: 'border-box',
  width: '100%',
};

const accentBarStyle: CSSProperties = {
  position: 'absolute',
  top: 0,
  left: 0,
  bottom: 0,
  width: 3,
  borderRadius: '3px 0 0 3px',
};

const iconContainerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  flexShrink: 0,
  marginTop: 1,
};

const contentContainerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: '2px',
  flex: 1,
  minWidth: 0,
};

const titleStyle: CSSProperties = {
  fontWeight: 'var(--ts-toast-title-font-weight)' as unknown as number,
  lineHeight: 1.4,
};

const descriptionStyle: CSSProperties = {
  color: 'var(--ts-toast-description-color)',
  fontSize: 'var(--ts-font-sm)',
  lineHeight: 1.4,
};

const actionButtonStyle: CSSProperties = {
  all: 'unset',
  color: 'var(--ts-toast-action-text)',
  fontWeight: 500,
  fontSize: 'var(--ts-font-sm)',
  cursor: 'pointer',
  marginTop: '4px',
};

const closeButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 20,
  height: 20,
  borderRadius: 'var(--ts-radius-sm)',
  color: 'var(--ts-toast-close-color)',
  cursor: 'pointer',
  flexShrink: 0,
  transition: 'color 100ms',
};

/* ----- Style injection --------------------------------------------------- */

const TOAST_STYLE_ID = 'ts-toast-styles';

function ensureToastStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(TOAST_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = TOAST_STYLE_ID;
  sheet.textContent = `
    [data-sonner-toaster] {
      --width: 356px;
      font-family: inherit;
    }
    [data-sonner-toast] {
      --normal-bg: var(--ts-toast-bg);
      --normal-border: var(--ts-toast-border);
      --normal-text: var(--ts-toast-text);
    }
    [data-ts-toast-close]:hover {
      color: var(--ts-text-primary);
    }
    [data-ts-toast-action]:hover {
      text-decoration: underline;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureToastStyles();
}

/* ----- Custom toast renderer --------------------------------------------- */

interface CustomToastProps {
  variant: ToastVariant;
  title: string;
  description?: string;
  action?: { label: string; onClick: () => void };
  onDismiss?: () => void;
}

function CustomToast({ variant, title, description, action, onDismiss }: CustomToastProps): React.JSX.Element {
  const config = variant !== 'default' ? VARIANT_CONFIG[variant] : null;

  return (
    <div style={toastBaseStyle} data-ts-toast-variant={variant}>
      {config ? (
        <div style={{ ...accentBarStyle, background: config.accentColor }} />
      ) : null}
      {config ? (
        <span style={{ ...iconContainerStyle, color: config.accentColor }}>
          {config.icon}
        </span>
      ) : null}
      <div style={contentContainerStyle}>
        <div style={titleStyle}>{title}</div>
        {description ? <div style={descriptionStyle}>{description}</div> : null}
        {action ? (
          <button
            type="button"
            data-ts-toast-action=""
            style={actionButtonStyle}
            onClick={action.onClick}
          >
            {action.label}
          </button>
        ) : null}
      </div>
      {onDismiss ? (
        <button
          type="button"
          data-ts-toast-close=""
          style={closeButtonStyle}
          onClick={onDismiss}
          aria-label="Dismiss"
        >
          <X size={14} />
        </button>
      ) : null}
    </div>
  );
}

/* ----- Toaster component (render once at app root) ----------------------- */

type ToasterPosition = 'top-left' | 'top-right' | 'top-center' | 'bottom-left' | 'bottom-right' | 'bottom-center';

interface ToasterProps {
  /** Position of the toast stack. */
  position?: ToasterPosition;
  /** Theme preference. */
  theme?: 'light' | 'dark' | 'system';
}

function Toaster({ position = 'bottom-right', theme = 'dark' }: ToasterProps): React.JSX.Element {
  return (
    <SonnerToaster
      position={position}
      theme={theme}
      toastOptions={{
        unstyled: true,
        style: {
          width: '100%',
        },
      }}
    />
  );
}

Toaster.displayName = 'Toaster';

/* ----- Toast trigger functions ------------------------------------------- */

interface ToastOptions {
  /** Toast title text. */
  title: string;
  /** Optional description text. */
  description?: string;
  /** Optional action button. */
  action?: { label: string; onClick: () => void };
  /** Duration in ms before auto-dismiss. */
  duration?: number;
}

function showToast(variant: ToastVariant, options: ToastOptions | string): string | number {
  const opts = typeof options === 'string' ? { title: options } : options;
  return toast.custom(
    (id) => (
      <CustomToast
        variant={variant}
        title={opts.title}
        description={opts.description}
        action={opts.action}
        onDismiss={() => toast.dismiss(id)}
      />
    ),
    { duration: opts.duration },
  );
}

/** Show a default toast. */
function toastDefault(options: ToastOptions | string): string | number {
  return showToast('default', options);
}

/** Show a success toast. */
toastDefault.success = (options: ToastOptions | string): string | number => {
  return showToast('success', options);
};

/** Show an error toast. */
toastDefault.error = (options: ToastOptions | string): string | number => {
  return showToast('error', options);
};

/** Show a warning toast. */
toastDefault.warning = (options: ToastOptions | string): string | number => {
  return showToast('warning', options);
};

/** Show an info toast. */
toastDefault.info = (options: ToastOptions | string): string | number => {
  return showToast('info', options);
};

/** Dismiss a specific toast or all toasts. */
toastDefault.dismiss = (id?: string | number): void => {
  if (id !== undefined) {
    toast.dismiss(id);
  } else {
    toast.dismiss();
  }
};

export { Toaster, toastDefault as toast, type ToastOptions, type ToasterProps };
