import { useState, useCallback, useRef, useEffect } from 'react';
import type { ColumnSizingState } from '@tanstack/react-table';

const DEBOUNCE_MS = 300;

function readFromStorage(key: string): ColumnSizingState {
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return {};
    const parsed: unknown = JSON.parse(raw);
    if (parsed !== null && typeof parsed === 'object' && !Array.isArray(parsed)) {
      return parsed as ColumnSizingState;
    }
    return {};
  } catch {
    return {};
  }
}

function writeToStorage(key: string, sizing: ColumnSizingState): void {
  try {
    localStorage.setItem(key, JSON.stringify(sizing));
  } catch {
    /* storage full or unavailable — non-critical */
  }
}

/**
 * Persists DataGrid column sizing to localStorage with debounced writes.
 * Key format: `ts-${storageKey}-column-sizing`
 */
export function usePersistedColumnSizing(storageKey: string): {
  columnSizing: ColumnSizingState;
  onColumnSizingChange: (sizing: ColumnSizingState) => void;
} {
  const fullKey = `ts-${storageKey}-column-sizing`;
  const [columnSizing, setColumnSizing] = useState<ColumnSizingState>(() => readFromStorage(fullKey));
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current !== null) {
        clearTimeout(timerRef.current);
      }
    };
  }, []);

  const onColumnSizingChange = useCallback(
    (sizing: ColumnSizingState) => {
      setColumnSizing(sizing);
      if (timerRef.current !== null) {
        clearTimeout(timerRef.current);
      }
      timerRef.current = setTimeout(() => {
        writeToStorage(fullKey, sizing);
        timerRef.current = null;
      }, DEBOUNCE_MS);
    },
    [fullKey],
  );

  return { columnSizing, onColumnSizingChange };
}
