/**
 * MessagePack-compatible binary codec for high-frequency FDC3 channel payloads.
 *
 * Uses a compact binary format that is 30-50% smaller than JSON for typical
 * market data payloads. Encodes primitives, arrays, objects, and null/undefined.
 *
 * This is a self-contained implementation with no external dependencies.
 */

/** Codec interface for encoding/decoding values to/from ArrayBuffer. */
export interface MessagePackCodec {
  encode<T>(value: T): ArrayBuffer;
  decode<T>(buffer: ArrayBuffer): T;
}

// MessagePack format markers
const FORMATS = {
  NIL: 0xc0,
  FALSE: 0xc2,
  TRUE: 0xc3,
  FLOAT64: 0xcb,
  UINT8: 0xcc,
  UINT16: 0xcd,
  UINT32: 0xce,
  INT8: 0xd0,
  INT16: 0xd1,
  INT32: 0xd2,
  STR8: 0xd9,
  STR16: 0xda,
  STR32: 0xdb,
  ARRAY16: 0xdc,
  ARRAY32: 0xdd,
  MAP16: 0xde,
  MAP32: 0xdf,
} as const;

const textEncoder = new TextEncoder();
const textDecoder = new TextDecoder();

class Encoder {
  private buffer: Uint8Array;
  private offset = 0;

  constructor(initialSize = 256) {
    this.buffer = new Uint8Array(initialSize);
  }

  private ensureCapacity(needed: number): void {
    const required = this.offset + needed;
    if (required <= this.buffer.length) return;
    let newSize = this.buffer.length * 2;
    while (newSize < required) newSize *= 2;
    const next = new Uint8Array(newSize);
    next.set(this.buffer);
    this.buffer = next;
  }

  private writeByte(value: number): void {
    this.ensureCapacity(1);
    this.buffer[this.offset++] = value;
  }

  private writeBytes(bytes: Uint8Array): void {
    this.ensureCapacity(bytes.length);
    this.buffer.set(bytes, this.offset);
    this.offset += bytes.length;
  }

  encode(value: unknown): ArrayBuffer {
    this.offset = 0;
    this.encodeValue(value);
    return (this.buffer.buffer as ArrayBuffer).slice(0, this.offset);
  }

  private encodeValue(value: unknown): void {
    if (value === null || value === undefined) {
      this.writeByte(FORMATS.NIL);
      return;
    }

    switch (typeof value) {
      case 'boolean':
        this.writeByte(value ? FORMATS.TRUE : FORMATS.FALSE);
        return;
      case 'number':
        this.encodeNumber(value);
        return;
      case 'string':
        this.encodeString(value);
        return;
      case 'object':
        if (Array.isArray(value)) {
          this.encodeArray(value);
        } else {
          this.encodeObject(value as Record<string, unknown>);
        }
        return;
    }
  }

  private encodeNumber(value: number): void {
    if (Number.isInteger(value)) {
      if (value >= 0) {
        if (value < 128) {
          // positive fixint
          this.writeByte(value);
        } else if (value <= 0xff) {
          this.writeByte(FORMATS.UINT8);
          this.writeByte(value);
        } else if (value <= 0xffff) {
          this.ensureCapacity(3);
          this.buffer[this.offset++] = FORMATS.UINT16;
          this.buffer[this.offset++] = (value >> 8) & 0xff;
          this.buffer[this.offset++] = value & 0xff;
        } else if (value <= 0xffffffff) {
          this.ensureCapacity(5);
          this.buffer[this.offset++] = FORMATS.UINT32;
          this.buffer[this.offset++] = (value >> 24) & 0xff;
          this.buffer[this.offset++] = (value >> 16) & 0xff;
          this.buffer[this.offset++] = (value >> 8) & 0xff;
          this.buffer[this.offset++] = value & 0xff;
        } else {
          this.encodeFloat64(value);
        }
      } else {
        if (value >= -32) {
          // negative fixint
          this.writeByte(value & 0xff);
        } else if (value >= -128) {
          this.writeByte(FORMATS.INT8);
          this.writeByte(value & 0xff);
        } else if (value >= -32768) {
          this.ensureCapacity(3);
          this.buffer[this.offset++] = FORMATS.INT16;
          this.buffer[this.offset++] = (value >> 8) & 0xff;
          this.buffer[this.offset++] = value & 0xff;
        } else if (value >= -2147483648) {
          this.ensureCapacity(5);
          this.buffer[this.offset++] = FORMATS.INT32;
          this.buffer[this.offset++] = (value >> 24) & 0xff;
          this.buffer[this.offset++] = (value >> 16) & 0xff;
          this.buffer[this.offset++] = (value >> 8) & 0xff;
          this.buffer[this.offset++] = value & 0xff;
        } else {
          this.encodeFloat64(value);
        }
      }
    } else {
      this.encodeFloat64(value);
    }
  }

  private encodeFloat64(value: number): void {
    this.ensureCapacity(9);
    this.buffer[this.offset++] = FORMATS.FLOAT64;
    const view = new DataView(this.buffer.buffer, this.offset, 8);
    view.setFloat64(0, value, false);
    this.offset += 8;
  }

  private encodeString(value: string): void {
    const bytes = textEncoder.encode(value);
    const len = bytes.length;

    if (len < 32) {
      // fixstr
      this.writeByte(0xa0 | len);
    } else if (len <= 0xff) {
      this.writeByte(FORMATS.STR8);
      this.writeByte(len);
    } else if (len <= 0xffff) {
      this.ensureCapacity(3);
      this.buffer[this.offset++] = FORMATS.STR16;
      this.buffer[this.offset++] = (len >> 8) & 0xff;
      this.buffer[this.offset++] = len & 0xff;
    } else {
      this.ensureCapacity(5);
      this.buffer[this.offset++] = FORMATS.STR32;
      this.buffer[this.offset++] = (len >> 24) & 0xff;
      this.buffer[this.offset++] = (len >> 16) & 0xff;
      this.buffer[this.offset++] = (len >> 8) & 0xff;
      this.buffer[this.offset++] = len & 0xff;
    }
    this.writeBytes(bytes);
  }

  private encodeArray(arr: unknown[]): void {
    const len = arr.length;
    if (len < 16) {
      // fixarray
      this.writeByte(0x90 | len);
    } else if (len <= 0xffff) {
      this.ensureCapacity(3);
      this.buffer[this.offset++] = FORMATS.ARRAY16;
      this.buffer[this.offset++] = (len >> 8) & 0xff;
      this.buffer[this.offset++] = len & 0xff;
    } else {
      this.ensureCapacity(5);
      this.buffer[this.offset++] = FORMATS.ARRAY32;
      this.buffer[this.offset++] = (len >> 24) & 0xff;
      this.buffer[this.offset++] = (len >> 16) & 0xff;
      this.buffer[this.offset++] = (len >> 8) & 0xff;
      this.buffer[this.offset++] = len & 0xff;
    }
    for (const item of arr) {
      this.encodeValue(item);
    }
  }

  private encodeObject(obj: Record<string, unknown>): void {
    const keys = Object.keys(obj);
    const len = keys.length;
    if (len < 16) {
      // fixmap
      this.writeByte(0x80 | len);
    } else if (len <= 0xffff) {
      this.ensureCapacity(3);
      this.buffer[this.offset++] = FORMATS.MAP16;
      this.buffer[this.offset++] = (len >> 8) & 0xff;
      this.buffer[this.offset++] = len & 0xff;
    } else {
      this.ensureCapacity(5);
      this.buffer[this.offset++] = FORMATS.MAP32;
      this.buffer[this.offset++] = (len >> 24) & 0xff;
      this.buffer[this.offset++] = (len >> 16) & 0xff;
      this.buffer[this.offset++] = (len >> 8) & 0xff;
      this.buffer[this.offset++] = len & 0xff;
    }
    for (const key of keys) {
      this.encodeString(key);
      this.encodeValue(obj[key]);
    }
  }
}

class Decoder {
  private data!: Uint8Array;
  private view!: DataView;
  private offset = 0;

  decode<T>(buffer: ArrayBuffer): T {
    this.data = new Uint8Array(buffer);
    this.view = new DataView(buffer);
    this.offset = 0;
    return this.decodeValue() as T;
  }

  private readByte(): number {
    return this.data[this.offset++]!;
  }

  private decodeValue(): unknown {
    const byte = this.readByte();

    // Positive fixint (0x00 - 0x7f)
    if (byte <= 0x7f) return byte;
    // Fixmap (0x80 - 0x8f)
    if (byte >= 0x80 && byte <= 0x8f) return this.decodeMap(byte & 0x0f);
    // Fixarray (0x90 - 0x9f)
    if (byte >= 0x90 && byte <= 0x9f) return this.decodeArray(byte & 0x0f);
    // Fixstr (0xa0 - 0xbf)
    if (byte >= 0xa0 && byte <= 0xbf) return this.decodeStr(byte & 0x1f);
    // Negative fixint (0xe0 - 0xff)
    if (byte >= 0xe0) return byte - 256;

    switch (byte) {
      case FORMATS.NIL: return null;
      case FORMATS.FALSE: return false;
      case FORMATS.TRUE: return true;
      case FORMATS.FLOAT64: {
        const val = this.view.getFloat64(this.offset, false);
        this.offset += 8;
        return val;
      }
      case FORMATS.UINT8: return this.readByte();
      case FORMATS.UINT16: {
        const val = this.view.getUint16(this.offset, false);
        this.offset += 2;
        return val;
      }
      case FORMATS.UINT32: {
        const val = this.view.getUint32(this.offset, false);
        this.offset += 4;
        return val;
      }
      case FORMATS.INT8: {
        const val = this.view.getInt8(this.offset);
        this.offset += 1;
        return val;
      }
      case FORMATS.INT16: {
        const val = this.view.getInt16(this.offset, false);
        this.offset += 2;
        return val;
      }
      case FORMATS.INT32: {
        const val = this.view.getInt32(this.offset, false);
        this.offset += 4;
        return val;
      }
      case FORMATS.STR8: return this.decodeStr(this.readByte());
      case FORMATS.STR16: {
        const len = this.view.getUint16(this.offset, false);
        this.offset += 2;
        return this.decodeStr(len);
      }
      case FORMATS.STR32: {
        const len = this.view.getUint32(this.offset, false);
        this.offset += 4;
        return this.decodeStr(len);
      }
      case FORMATS.ARRAY16: {
        const len = this.view.getUint16(this.offset, false);
        this.offset += 2;
        return this.decodeArray(len);
      }
      case FORMATS.ARRAY32: {
        const len = this.view.getUint32(this.offset, false);
        this.offset += 4;
        return this.decodeArray(len);
      }
      case FORMATS.MAP16: {
        const len = this.view.getUint16(this.offset, false);
        this.offset += 2;
        return this.decodeMap(len);
      }
      case FORMATS.MAP32: {
        const len = this.view.getUint32(this.offset, false);
        this.offset += 4;
        return this.decodeMap(len);
      }
      default:
        throw new Error(`Unknown MessagePack format byte: 0x${byte.toString(16)}`);
    }
  }

  private decodeStr(length: number): string {
    const bytes = this.data.subarray(this.offset, this.offset + length);
    this.offset += length;
    return textDecoder.decode(bytes);
  }

  private decodeArray(length: number): unknown[] {
    const arr: unknown[] = [];
    for (let i = 0; i < length; i++) {
      arr.push(this.decodeValue());
    }
    return arr;
  }

  private decodeMap(length: number): Record<string, unknown> {
    const obj: Record<string, unknown> = {};
    for (let i = 0; i < length; i++) {
      const key = this.decodeValue() as string;
      obj[key] = this.decodeValue();
    }
    return obj;
  }
}

/** Create a MessagePack codec for encoding/decoding binary payloads. */
export function createMessagePackCodec(): MessagePackCodec {
  const encoder = new Encoder();
  const decoder = new Decoder();

  return {
    encode<T>(value: T): ArrayBuffer {
      return encoder.encode(value);
    },
    decode<T>(buffer: ArrayBuffer): T {
      return decoder.decode<T>(buffer);
    },
  };
}
