import { forwardRef, type CSSProperties, type ReactNode } from 'react';
import { Settings } from 'lucide-react';
import { Toolbar } from '../../primitives';

/* -------------------------------------------------------------------------- */
/*  AppHeader                                                                 */
/*  Standardized app header with title, optional icon, settings button, and   */
/*  actions slot. No channel indicator — Desk title bar owns that.            */
/*  Uses --ts-app-header-* tokens.                                            */
/* -------------------------------------------------------------------------- */

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-app-header-styles';

function ensureAppHeaderStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-app-header] [data-ts-app-header-spacer] {
      flex: 1;
      min-width: 0;
    }
    [data-ts-app-header] [data-ts-app-header-settings]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAppHeaderStyles();
}

/* ----- Types ------------------------------------------------------------- */

export interface AppHeaderProps {
  /** App title text. */
  title: string;
  /** Optional app icon (ReactNode, typically a Lucide icon). */
  icon?: ReactNode;
  /** Actions slot rendered at the right side of the header. */
  actions?: ReactNode;
  /** Called when the settings button is clicked. */
  onSettingsClick?: () => void;
  /** Whether to show the settings gear icon. Default true. */
  showSettings?: boolean;
}

/* ----- Styles ------------------------------------------------------------ */

const wrapperStyle: CSSProperties = {
  display: 'contents',
};

const titleAreaStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const iconStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: 'var(--ts-app-header-icon-color)',
  flexShrink: 0,
};

const titleTextStyle: CSSProperties = {
  fontSize: 'var(--ts-app-header-title-font-size)',
  fontWeight: 'var(--ts-app-header-title-font-weight)' as unknown as number,
  color: 'var(--ts-app-header-title-text)',
  lineHeight: 1,
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
};

const actionsAreaStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
};

const settingsButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-icon-button-size-sm)',
  height: 'var(--ts-icon-button-size-sm)',
  borderRadius: 'var(--ts-button-radius)',
  background: 'transparent',
  color: 'var(--ts-text-secondary)',
  cursor: 'pointer',
  transition: 'background 100ms, color 100ms',
  boxSizing: 'border-box',
};

const toolbarOverride: CSSProperties = {
  height: 'var(--ts-app-shell-header-height)',
  background: 'var(--ts-app-header-bg)',
  borderBottom: '1px solid var(--ts-app-header-border)',
};

/* ----- Component --------------------------------------------------------- */

export const AppHeader = forwardRef<HTMLDivElement, AppHeaderProps>(
  function AppHeader(
    { title, icon, actions, onSettingsClick, showSettings = true },
    ref,
  ) {
    return (
      <div role="banner" data-ts-app-header="" style={{ display: 'contents' }}>
        <Toolbar ref={ref} className={undefined}>
          <div style={{ ...wrapperStyle, ...toolbarOverride, display: 'flex', alignItems: 'center', width: '100%', padding: '0 var(--ts-toolbar-padding-x)', gap: 'var(--ts-toolbar-item-gap)' }}>
            <div style={titleAreaStyle}>
              {icon !== undefined && icon !== null ? (
                <span style={iconStyle}>{icon}</span>
              ) : null}
              <span style={titleTextStyle}>{title}</span>
            </div>
            <div data-ts-app-header-spacer="" style={{ flex: 1, minWidth: 0 }} />
            {actions !== undefined && actions !== null ? (
              <div style={actionsAreaStyle}>{actions}</div>
            ) : null}
            {showSettings ? (
              <button
                type="button"
                data-ts-app-header-settings=""
                aria-label="Settings"
                style={settingsButtonStyle}
                onClick={onSettingsClick}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = 'var(--ts-button-ghost-bg-hover)';
                  e.currentTarget.style.color = 'var(--ts-text-primary)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = 'transparent';
                  e.currentTarget.style.color = 'var(--ts-text-secondary)';
                }}
              >
                <Settings size={16} />
              </button>
            ) : null}
          </div>
        </Toolbar>
      </div>
    );
  },
);

AppHeader.displayName = 'AppHeader';
