/**
 * WCP (Web Connection Protocol) client for iframe-hosted FDC3 apps.
 *
 * When an app is running inside an iframe (window.parent !== window) and
 * window.fdc3 is not already set, this module performs the WCP handshake
 * with the parent shell's WcpBridge and installs a DesktopAgent proxy as
 * window.fdc3.
 *
 * Import this module early (it's re-exported from the package index) so the
 * handshake starts before React mounts. The useFdc3() hook will pick up the
 * agent via the fdc3Ready event.
 */

import type { DesktopAgent, Context, Listener, ContextHandler, IntentResolution, AppIdentifier, Channel, AppIntent, ImplementationMetadata } from "./fdc3-types";

// Only activate inside an iframe where window.fdc3 isn't already set.
const isIframe = typeof window !== "undefined" && window.parent !== window;

if (isIframe && !window.fdc3) {
  initWcpClient();
}

function initWcpClient(): void {
  // Pending DACP request/response correlation
  const pendingRequests = new Map<string, { resolve: (v: unknown) => void; reject: (e: Error) => void }>();

  // Registered handlers
  const contextHandlers = new Map<string, { contextType: string | null; handler: ContextHandler }>();
  const intentHandlers = new Map<string, { intentName: string; handler: (context: Context, metadata?: { source: AppIdentifier }) => void }>();

  // Send a message to the parent shell
  function sendToParent(msg: unknown): void {
    try {
      window.parent.postMessage(msg, "*");
    } catch {
      // Parent may not be accessible
    }
  }

  // Send a DACP request and wait for the response
  function dacpRequest(method: string, payload: Record<string, unknown> = {}): Promise<unknown> {
    return new Promise((resolve, reject) => {
      const uuid = crypto.randomUUID();
      pendingRequests.set(uuid, { resolve, reject });
      sendToParent({
        type: method,
        payload,
        meta: { requestUuid: uuid, timestamp: new Date().toISOString() },
      });
      // Timeout after 10s
      setTimeout(() => {
        if (pendingRequests.has(uuid)) {
          pendingRequests.delete(uuid);
          reject(new Error(`DACP timeout: ${method}`));
        }
      }, 10000);
    });
  }

  // Listen for messages from the parent
  window.addEventListener("message", (event: MessageEvent) => {
    const data = event.data;
    if (!data || typeof data !== "object" || !data.type) return;

    // WCP3 Handshake response — install the agent
    if (data.type === "wcp3Handshake") {
      installAgent();
      return;
    }

    // WCP5 Channel Selector — acknowledge
    if (data.type === "wcp5ChannelSelector") return;

    // Context broadcast event from parent
    if (data.type === "broadcastEvent") {
      const ctx = data.payload?.context as Context | undefined;
      if (!ctx) return;
      for (const [, h] of contextHandlers) {
        if (h.contextType === null || h.contextType === ctx.type) {
          try {
            h.handler(ctx);
          } catch (e) {
            console.error("[wcp-client] context handler error:", e);
          }
        }
      }
      return;
    }

    // Intent event from parent
    if (data.type === "intentEvent") {
      const intent = data.payload?.intent as string | undefined;
      const ictx = data.payload?.context as Context | undefined;
      if (!intent || !ictx) return;
      for (const [, h] of intentHandlers) {
        if (h.intentName === intent) {
          try {
            h.handler(ictx, { source: data.payload.originatingApp ?? { appId: "unknown" } });
          } catch (e) {
            console.error("[wcp-client] intent handler error:", e);
          }
        }
      }
      return;
    }

    // Channel changed / private channel events — acknowledge
    if (data.type === "channelChanged" || data.type === "privateChannelEvent") return;

    // DACP response (matches a pending request)
    const requestUuid = data.meta?.requestUuid as string | undefined;
    if (requestUuid && pendingRequests.has(requestUuid)) {
      const pending = pendingRequests.get(requestUuid)!;
      pendingRequests.delete(requestUuid);
      if (data.payload?.error) {
        pending.reject(new Error(data.payload.error as string));
      } else {
        pending.resolve(data.payload?.result ?? null);
      }
    }
  });

  // Create and install the DesktopAgent proxy
  function installAgent(): void {
    const agent: DesktopAgent = {
      broadcast(context: Context): Promise<void> {
        return dacpRequest("broadcast", { context }) as Promise<void>;
      },

      addContextListener(
        contextType: string | null,
        handler: ContextHandler,
      ): Promise<Listener> {
        const listenerId = crypto.randomUUID();
        contextHandlers.set(listenerId, { contextType, handler });
        return dacpRequest("addContextListener", {
          contextType,
          listenerId,
        }).then(() => ({
          unsubscribe(): void {
            contextHandlers.delete(listenerId);
            dacpRequest("removeContextListener", { contextType, listenerId }).catch(() => {});
          },
        }));
      },

      raiseIntent(
        intent: string,
        context: Context,
        app?: AppIdentifier | string,
      ): Promise<IntentResolution> {
        const targetApp = typeof app === "string" ? { appId: app } : app;
        return dacpRequest("raiseIntent", {
          intent,
          context,
          targetApp,
        }).then((raw: unknown) => {
          const r = (raw ?? {}) as Record<string, unknown>;
          return {
            source: (r.source ?? { appId: "unknown" }) as AppIdentifier,
            intent: (r.intent as string) ?? intent,
            getResult(): Promise<Context | Channel | void> {
              if (r.result_id) {
                return dacpRequest("getIntentResult", { resultId: r.result_id }) as Promise<Context | Channel | void>;
              }
              return Promise.resolve(undefined);
            },
          };
        });
      },

      addIntentListener(
        intent: string,
        handler: (context: Context) => Promise<Context | Channel | void>,
      ): Promise<Listener> {
        const listenerId = crypto.randomUUID();
        intentHandlers.set(listenerId, { intentName: intent, handler: handler as never });
        return dacpRequest("addIntentListener", {
          intent,
          listenerId,
        }).then(() => ({
          unsubscribe(): void {
            intentHandlers.delete(listenerId);
            dacpRequest("removeIntentListener", { intent, listenerId }).catch(() => {});
          },
        }));
      },

      getUserChannels(): Promise<Channel[]> {
        return dacpRequest("getUserChannels") as Promise<Channel[]>;
      },

      getOrCreateChannel(channelId: string): Promise<Channel> {
        return dacpRequest("getOrCreateChannel", { channelId }) as Promise<Channel>;
      },

      joinUserChannel(channelId: string): Promise<void> {
        return dacpRequest("joinUserChannel", { channelId }) as Promise<void>;
      },

      getCurrentChannel(): Promise<Channel | null> {
        return dacpRequest("getCurrentChannel") as Promise<Channel | null>;
      },

      leaveCurrentChannel(): Promise<void> {
        return dacpRequest("leaveCurrentChannel") as Promise<void>;
      },

      createPrivateChannel(): Promise<Channel> {
        return dacpRequest("createPrivateChannel") as Promise<Channel>;
      },

      addEventListener(_type: string, _handler: (...args: unknown[]) => void): Promise<Listener> {
        return Promise.resolve({ unsubscribe() {} });
      },

      getInfo(): ImplementationMetadata {
        return {
          fdc3Version: "2.0",
          provider: "DeskModal",
          providerVersion: "0.1.0",
        };
      },

      findIntent(intent: string, context?: Context, resultType?: string): Promise<AppIntent> {
        return dacpRequest("findIntent", { intent, context, resultType }) as Promise<AppIntent>;
      },

      findIntentsByContext(context: Context, resultType?: string): Promise<AppIntent[]> {
        return dacpRequest("findIntentsByContext", { context, resultType }) as Promise<AppIntent[]>;
      },

      open(app: AppIdentifier, context?: Context): Promise<AppIdentifier> {
        return dacpRequest("open", { appId: app.appId, context }) as Promise<AppIdentifier>;
      },
    };

    window.fdc3 = agent;
    window.dispatchEvent(new Event("fdc3Ready"));
  }

  // Initiate WCP handshake with the parent shell
  sendToParent({
    type: "wcp1Hello",
    payload: {
      fdc3Version: "2.0",
      identityUrl: window.location.href,
      actualUrl: window.location.href,
    },
    meta: {
      connectionAttemptUuid: crypto.randomUUID(),
      timestamp: new Date().toISOString(),
    },
  });
}
