import { useCallback, type CSSProperties } from 'react';
import { DropdownMenu } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  LineStylePicker                                                           */
/*  Dropdown picker for line dash styles (solid, dashed, dotted, dash-dot).   */
/*  Uses --ts-overlay-* and --ts-menu-* tokens.                               */
/* -------------------------------------------------------------------------- */

export type LineStyle = 'solid' | 'dashed' | 'dotted' | 'dash-dot';

export interface LineStylePickerProps {
  /** Current line style value. */
  value: LineStyle;
  /** Called when a new style is selected. */
  onValueChange: (style: LineStyle) => void;
  /** Whether the picker is disabled. */
  disabled?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-line-style-picker-styles';

function ensureLineStylePickerStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-line-style-picker]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-line-style-picker]:not(:disabled):hover {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-line-style-picker]:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureLineStylePickerStyles();
}

/* ----- Line style SVG definitions ---------------------------------------- */

const LINE_STYLE_OPTIONS: { style: LineStyle; label: string; dashArray: string }[] = [
  { style: 'solid', label: 'Solid', dashArray: '' },
  { style: 'dashed', label: 'Dashed', dashArray: '6 3' },
  { style: 'dotted', label: 'Dotted', dashArray: '2 2' },
  { style: 'dash-dot', label: 'Dash Dot', dashArray: '6 2 2 2' },
];

function getStrokeDashArray(style: LineStyle): string {
  const opt = LINE_STYLE_OPTIONS.find((o) => o.style === style);
  return opt?.dashArray ?? '';
}

/* ----- Styles ------------------------------------------------------------ */

const triggerStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-icon-button-size-md)',
  height: 'var(--ts-icon-button-size-md)',
  borderRadius: 'var(--ts-button-radius)',
  border: '1px solid var(--ts-button-ghost-border)',
  background: 'var(--ts-button-ghost-bg)',
  color: 'var(--ts-button-ghost-text)',
  cursor: 'pointer',
  boxSizing: 'border-box',
  transition: 'background 150ms',
  flexShrink: 0,
};

const menuItemContentStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  width: '100%',
};

const menuItemLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
  color: 'inherit',
};

/* ----- SVG preview component --------------------------------------------- */

function LineStylePreview({
  dashArray,
  width = 40,
  height = 20,
}: {
  dashArray: string;
  width?: number;
  height?: number;
}): React.JSX.Element {
  return (
    <svg
      data-ts-line-style-preview=""
      viewBox={`0 0 ${width} ${height}`}
      width={width}
      height={height}
      aria-hidden="true"
      style={{ flexShrink: 0 }}
    >
      <line
        x1="2"
        y1={height / 2}
        x2={width - 2}
        y2={height / 2}
        stroke="currentColor"
        strokeWidth="2"
        strokeDasharray={dashArray || undefined}
        strokeLinecap="round"
      />
    </svg>
  );
}

/* ----- Component --------------------------------------------------------- */

export function LineStylePicker({
  value,
  onValueChange,
  disabled = false,
}: LineStylePickerProps): React.JSX.Element {
  const handleSelect = useCallback((style: LineStyle) => {
    onValueChange(style);
  }, [onValueChange]);

  const currentDash = getStrokeDashArray(value);

  return (
    <DropdownMenu>
      <DropdownMenu.Trigger>
        <button
          type="button"
          data-ts-line-style-picker=""
          disabled={disabled}
          aria-label="Pick line style"
          style={triggerStyle}
        >
          <LineStylePreview dashArray={currentDash} width={24} height={16} />
        </button>
      </DropdownMenu.Trigger>
      <DropdownMenu.Content align="start">
        {LINE_STYLE_OPTIONS.map((opt) => (
          <DropdownMenu.Item
            key={opt.style}
            onSelect={() => handleSelect(opt.style)}
            data-style={opt.style}
          >
            <div style={menuItemContentStyle}>
              <LineStylePreview dashArray={opt.dashArray} />
              <span style={menuItemLabelStyle}>{opt.label}</span>
            </div>
          </DropdownMenu.Item>
        ))}
      </DropdownMenu.Content>
    </DropdownMenu>
  );
}

LineStylePicker.displayName = 'LineStylePicker';
