import { forwardRef, type CSSProperties, type ReactNode, type ElementRef, type ComponentPropsWithoutRef } from 'react';
import { Dialog as DialogPrimitive } from 'radix-ui';
import { X } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  Dialog                                                                    */
/*  Modal dialog with backdrop, title, description, and close button.         */
/*  Wraps Radix Dialog — uses --ts-dialog-* tokens.                           */
/* -------------------------------------------------------------------------- */

/* ----- Style injection --------------------------------------------------- */

const DIALOG_STYLE_ID = 'ts-dialog-styles';

function ensureDialogStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(DIALOG_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = DIALOG_STYLE_ID;
  sheet.textContent = `
    @keyframes ts-dialog-overlay-in {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    @keyframes ts-dialog-overlay-out {
      from { opacity: 1; }
      to { opacity: 0; }
    }
    @keyframes ts-dialog-content-in {
      from { opacity: 0; transform: translate(-50%, -50%) scale(0.96); }
      to { opacity: 1; transform: translate(-50%, -50%) scale(1); }
    }
    @keyframes ts-dialog-content-out {
      from { opacity: 1; transform: translate(-50%, -50%) scale(1); }
      to { opacity: 0; transform: translate(-50%, -50%) scale(0.96); }
    }
    [data-ts-dialog-overlay][data-state="open"] {
      animation: ts-dialog-overlay-in 200ms ease-out;
    }
    [data-ts-dialog-overlay][data-state="closed"] {
      animation: ts-dialog-overlay-out 150ms ease-in;
    }
    [data-ts-dialog-content][data-state="open"] {
      animation: ts-dialog-content-in 200ms ease-out;
    }
    [data-ts-dialog-content][data-state="closed"] {
      animation: ts-dialog-content-out 150ms ease-in;
    }
    [data-ts-dialog-close]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-dialog-overlay][data-state="open"],
      [data-ts-dialog-overlay][data-state="closed"],
      [data-ts-dialog-content][data-state="open"],
      [data-ts-dialog-content][data-state="closed"] {
        animation: none;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureDialogStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const overlayStyle: CSSProperties = {
  position: 'fixed',
  inset: 0,
  background: 'var(--ts-dialog-backdrop)',
  zIndex: 50,
};

const dialogContentStyle: CSSProperties = {
  position: 'fixed',
  top: '50%',
  left: '50%',
  transform: 'translate(-50%, -50%)',
  background: 'var(--ts-dialog-bg)',
  border: '1px solid var(--ts-dialog-border)',
  borderRadius: 'var(--ts-dialog-radius)',
  boxShadow: 'var(--ts-dialog-shadow)',
  padding: 'var(--ts-dialog-padding)',
  width: '90vw',
  maxWidth: 'var(--ts-dialog-max-width)',
  maxHeight: '85vh',
  overflowY: 'auto',
  zIndex: 51,
  outline: 'none',
  boxSizing: 'border-box',
  fontFamily: 'inherit',
};

const closeButtonStyle: CSSProperties = {
  all: 'unset',
  position: 'absolute',
  top: '16px',
  right: '16px',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 24,
  height: 24,
  borderRadius: 'var(--ts-radius-sm)',
  color: 'var(--ts-text-tertiary)',
  cursor: 'pointer',
  transition: 'color 100ms, background 100ms',
  boxSizing: 'border-box',
};

const titleStyle: CSSProperties = {
  margin: 0,
  fontSize: 'var(--ts-dialog-title-font-size)',
  fontWeight: 'var(--ts-dialog-title-font-weight)' as unknown as number,
  fontFamily: 'inherit',
  color: 'var(--ts-text-primary)',
  lineHeight: 1.3,
  paddingRight: '32px',
};

const descriptionStyle: CSSProperties = {
  margin: 0,
  marginTop: 'var(--ts-dialog-header-gap)',
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
  color: 'var(--ts-text-secondary)',
  lineHeight: 1.5,
};

/* ----- Dialog.Root -------------------------------------------------------- */

type DialogRootProps = ComponentPropsWithoutRef<typeof DialogPrimitive.Root>;

function Root(props: DialogRootProps): React.JSX.Element {
  return <DialogPrimitive.Root {...props} />;
}
Root.displayName = 'Dialog';

/* ----- Dialog.Trigger ---------------------------------------------------- */

type DialogTriggerProps = ComponentPropsWithoutRef<typeof DialogPrimitive.Trigger>;

const DialogTrigger = forwardRef<ElementRef<typeof DialogPrimitive.Trigger>, DialogTriggerProps>(
  (props, ref) => <DialogPrimitive.Trigger ref={ref} asChild {...props} />,
);
DialogTrigger.displayName = 'Dialog.Trigger';

/* ----- Dialog.Content ---------------------------------------------------- */

interface DialogContentProps extends ComponentPropsWithoutRef<typeof DialogPrimitive.Content> {
  /** Content inside the dialog panel. */
  children: ReactNode;
  /** Whether to show the close button. Defaults to true. */
  showClose?: boolean;
}

const DialogContent = forwardRef<ElementRef<typeof DialogPrimitive.Content>, DialogContentProps>(
  ({ children, style, showClose = true, ...props }, ref) => (
    <DialogPrimitive.Portal>
      <DialogPrimitive.Overlay data-ts-dialog-overlay="" style={overlayStyle} />
      <DialogPrimitive.Content
        ref={ref}
        data-ts-dialog-content=""
        style={{ ...dialogContentStyle, ...style }}
        {...props}
      >
        {children}
        {showClose ? (
          <DialogPrimitive.Close
            data-ts-dialog-close=""
            style={closeButtonStyle}
            onMouseEnter={(e) => {
              e.currentTarget.style.color = 'var(--ts-text-primary)';
              e.currentTarget.style.background = 'var(--ts-menu-item-bg-hover)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.color = 'var(--ts-text-tertiary)';
              e.currentTarget.style.background = 'transparent';
            }}
            aria-label="Close"
          >
            <X size={16} />
          </DialogPrimitive.Close>
        ) : null}
      </DialogPrimitive.Content>
    </DialogPrimitive.Portal>
  ),
);
DialogContent.displayName = 'Dialog.Content';

/* ----- Dialog.Title ------------------------------------------------------ */

type DialogTitleProps = ComponentPropsWithoutRef<typeof DialogPrimitive.Title>;

const DialogTitle = forwardRef<ElementRef<typeof DialogPrimitive.Title>, DialogTitleProps>(
  ({ style, ...props }, ref) => (
    <DialogPrimitive.Title
      ref={ref}
      style={{ ...titleStyle, ...style }}
      {...props}
    />
  ),
);
DialogTitle.displayName = 'Dialog.Title';

/* ----- Dialog.Description ------------------------------------------------ */

type DialogDescriptionProps = ComponentPropsWithoutRef<typeof DialogPrimitive.Description>;

const DialogDescription = forwardRef<ElementRef<typeof DialogPrimitive.Description>, DialogDescriptionProps>(
  ({ style, ...props }, ref) => (
    <DialogPrimitive.Description
      ref={ref}
      style={{ ...descriptionStyle, ...style }}
      {...props}
    />
  ),
);
DialogDescription.displayName = 'Dialog.Description';

/* ----- Dialog.Close ------------------------------------------------------ */

type DialogCloseProps = ComponentPropsWithoutRef<typeof DialogPrimitive.Close>;

const DialogClose = forwardRef<ElementRef<typeof DialogPrimitive.Close>, DialogCloseProps>(
  (props, ref) => <DialogPrimitive.Close ref={ref} asChild {...props} />,
);
DialogClose.displayName = 'Dialog.Close';

/* ----- Compound export --------------------------------------------------- */

export const Dialog = Object.assign(Root, {
  Root,
  Trigger: DialogTrigger,
  Content: DialogContent,
  Title: DialogTitle,
  Description: DialogDescription,
  Close: DialogClose,
});
