import { forwardRef, useCallback, type CSSProperties } from 'react';
import { Lock, Unlock } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  LockDrawingsButton                                                        */
/*  Toggle button to lock/unlock all drawings on the chart.                   */
/*  Uses --ts-button-ghost-*, --ts-accent-* tokens.                           */
/* -------------------------------------------------------------------------- */

export interface LockDrawingsButtonProps {
  /** Whether all drawings are locked. */
  locked: boolean;
  /** Called when lock state changes. */
  onLockedChange: (locked: boolean) => void;
}

/* ----- Style injection for hover/focus states ----------------------------- */

const LOCK_DRAWINGS_STYLE_ID = 'ts-lock-drawings-styles';

function ensureLockDrawingsStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(LOCK_DRAWINGS_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = LOCK_DRAWINGS_STYLE_ID;
  sheet.textContent = `
    [data-ts-lock-drawings]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-lock-drawings]:not([data-active]):hover {
      background: var(--ts-button-ghost-bg-hover);
      color: var(--ts-button-ghost-text-hover);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureLockDrawingsStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const baseStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-icon-button-size-sm)',
  height: 'var(--ts-icon-button-size-sm)',
  borderRadius: 'var(--ts-button-radius)',
  cursor: 'pointer',
  flexShrink: 0,
  boxSizing: 'border-box',
  transition: 'background 150ms, color 150ms',
};

function getStyle(isActive: boolean): CSSProperties {
  return {
    ...baseStyle,
    background: isActive ? 'var(--ts-accent-subtle)' : 'var(--ts-button-ghost-bg)',
    color: isActive ? 'var(--ts-accent-default)' : 'var(--ts-button-ghost-text)',
    border: '1px solid var(--ts-button-ghost-border)',
  };
}

export const LockDrawingsButton = forwardRef<HTMLButtonElement, LockDrawingsButtonProps>(
  function LockDrawingsButton({ locked, onLockedChange }, ref) {
    const label = locked ? 'Unlock all drawings' : 'Lock all drawings';

    const handleClick = useCallback(() => {
      onLockedChange(!locked);
    }, [locked, onLockedChange]);

    return (
      <button
        ref={ref}
        type="button"
        data-ts-lock-drawings=""
        {...(locked ? { 'data-active': '' } : {})}
        style={getStyle(locked)}
        aria-label={label}
        aria-pressed={locked}
        title={label}
        onClick={handleClick}
      >
        {locked ? <Lock size={16} /> : <Unlock size={16} />}
      </button>
    );
  },
);

LockDrawingsButton.displayName = 'LockDrawingsButton';
