import { useCallback, type CSSProperties } from 'react';
import { GripVertical } from 'lucide-react';
import { Dialog, Checkbox, Button } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  WatchlistColumnConfig                                                      */
/*  Dialog for configuring visible columns and their order.                    */
/*  Composes Dialog, Checkbox, Button from Phase 0 primitives.                 */
/* -------------------------------------------------------------------------- */

export interface ColumnConfig {
  /** Column identifier. */
  id: string;
  /** Display label. */
  label: string;
  /** Whether the column is currently visible. */
  visible: boolean;
  /** Whether the column can be hidden (Symbol column cannot). */
  removable: boolean;
}

export interface WatchlistColumnConfigProps {
  /** All available columns with their visibility state. */
  columns: ColumnConfig[];
  /** Whether the dialog is open. */
  open: boolean;
  /** Called when the dialog should close. */
  onOpenChange: (open: boolean) => void;
  /** Called when column visibility or order changes. */
  onColumnsChange: (columns: ColumnConfig[]) => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-column-config-styles';

function ensureColumnConfigStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-column-config-item]:hover {
      background: var(--ts-data-row-bg-hover);
    }
    [data-ts-column-config-item][draggable="true"] {
      cursor: grab;
    }
    [data-ts-column-config-item][draggable="true"]:active {
      cursor: grabbing;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureColumnConfigStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const listStyle: CSSProperties = {
  listStyle: 'none',
  margin: 'var(--ts-space-4) 0',
  padding: 0,
  maxHeight: '320px',
  overflowY: 'auto',
};

const itemStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-2) var(--ts-space-3)',
  borderRadius: 'var(--ts-radius-sm)',
  transition: 'background 100ms',
};

const gripStyle: CSSProperties = {
  flexShrink: 0,
  color: 'var(--ts-text-tertiary)',
  cursor: 'grab',
};

const itemLabelStyle: CSSProperties = {
  flex: 1,
  fontSize: 'var(--ts-font-md)',
  color: 'var(--ts-text-primary)',
};

const footerStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'flex-end',
  gap: 'var(--ts-dialog-footer-gap)',
  marginTop: 'var(--ts-space-4)',
};

/* ----- Component --------------------------------------------------------- */

export function WatchlistColumnConfig({
  columns,
  open,
  onOpenChange,
  onColumnsChange,
}: WatchlistColumnConfigProps): React.JSX.Element {
  const handleVisibilityChange = useCallback(
    (columnId: string, visible: boolean) => {
      const updated = columns.map((col) =>
        col.id === columnId ? { ...col, visible } : col,
      );
      onColumnsChange(updated);
    },
    [columns, onColumnsChange],
  );

  const handleDragStart = useCallback(
    (e: React.DragEvent<HTMLLIElement>, index: number) => {
      e.dataTransfer.setData('text/plain', String(index));
      e.dataTransfer.effectAllowed = 'move';
    },
    [],
  );

  const handleDragOver = useCallback((e: React.DragEvent<HTMLLIElement>) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  }, []);

  const handleDrop = useCallback(
    (e: React.DragEvent<HTMLLIElement>, targetIndex: number) => {
      e.preventDefault();
      const sourceIndex = parseInt(e.dataTransfer.getData('text/plain'), 10);
      if (isNaN(sourceIndex) || sourceIndex === targetIndex) return;

      const reordered = [...columns];
      const removed = reordered.splice(sourceIndex, 1);
      const moved = removed[0];
      if (moved) {
        reordered.splice(targetIndex, 0, moved);
        onColumnsChange(reordered);
      }
    },
    [columns, onColumnsChange],
  );

  const handleReset = useCallback(() => {
    const reset = columns.map((col) => ({ ...col, visible: true }));
    onColumnsChange(reset);
  }, [columns, onColumnsChange]);

  const handleDone = useCallback(() => {
    onOpenChange(false);
  }, [onOpenChange]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content data-ts-column-config="" data-testid="column-config-dialog" style={{ maxWidth: '360px' }}>
        <Dialog.Title>Configure Columns</Dialog.Title>
        <ul style={listStyle} data-testid="column-config-list">
          {columns.map((col, index) => (
            <li
              key={col.id}
              data-ts-column-config-item=""
              style={itemStyle}
              draggable={col.removable}
              onDragStart={(e) => handleDragStart(e, index)}
              onDragOver={handleDragOver}
              onDrop={(e) => handleDrop(e, index)}
              data-testid={`column-config-item-${col.id}`}
            >
              {col.removable && (
                <span style={gripStyle} aria-hidden="true">
                  <GripVertical size={14} />
                </span>
              )}
              <span data-testid={`column-config-checkbox-${col.id}`}>
                <Checkbox
                  checked={col.visible}
                  onCheckedChange={(checked: boolean | 'indeterminate') => handleVisibilityChange(col.id, checked === true)}
                  disabled={!col.removable}
                />
              </span>
              <span style={itemLabelStyle}>{col.label}</span>
            </li>
          ))}
        </ul>
        <div style={footerStyle}>
          <Button variant="secondary" onClick={handleReset} data-testid="column-config-reset">
            Reset to Default
          </Button>
          <Dialog.Close>
            <Button variant="primary" onClick={handleDone} data-testid="column-config-done">
              Done
            </Button>
          </Dialog.Close>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

WatchlistColumnConfig.displayName = 'WatchlistColumnConfig';
