import { forwardRef, type CSSProperties } from 'react';
import { IconButton, Tooltip } from '../primitives';
import { Plus } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  CompareButton                                                             */
/*  Single IconButton with Plus icon for compare/add symbol functionality.   */
/*  Uses IconButton + Tooltip with --ts-button-ghost-* tokens.               */
/* -------------------------------------------------------------------------- */

export interface CompareButtonProps {
  /** Called when the button is clicked (opens compare symbol input). */
  onClick?: () => void;
  /** Whether compare mode is active. */
  active?: boolean;
  /** Tooltip label. Default "Compare or Add Symbol". */
  label?: string;
  /** Whether the button is disabled. */
  disabled?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-compare-button-styles';

function ensureCompareButtonStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-compare-button]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureCompareButtonStyles();
}

/* ----- Component --------------------------------------------------------- */

export const CompareButton = forwardRef<HTMLButtonElement, CompareButtonProps>(
  function CompareButton(
    {
      onClick,
      active = false,
      label = 'Compare or Add Symbol',
      disabled = false,
    },
    ref,
  ) {
    return (
      <Tooltip content={label} side="bottom">
        <IconButton
          ref={ref}
          data-ts-compare-button=""
          icon={<Plus size={16} />}
          label={label}
          variant="ghost"
          size="sm"
          active={active}
          disabled={disabled}
          onClick={onClick}
        />
      </Tooltip>
    );
  },
);

CompareButton.displayName = 'CompareButton';
