import { useCallback, type CSSProperties, type ReactNode, type KeyboardEvent } from 'react';
import { ChevronDown, ChevronRight } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  AlertGroupHeader                                                          */
/*  Collapsible group header for alert lists with label, count, and icon.     */
/*  Used by AlertManagerPanel for grouping by symbol or status.               */
/*  Uses --ts-panel-*, --ts-border-* tokens.                                  */
/* -------------------------------------------------------------------------- */

export interface AlertGroupHeaderProps {
  /** Group label (e.g., "BTCUSDT" or "Active"). */
  label: string;
  /** Number of alerts in this group. */
  count: number;
  /** Whether the group is expanded. */
  expanded: boolean;
  /** Called when expand/collapse is toggled. */
  onExpandedChange: (expanded: boolean) => void;
  /** Optional icon (e.g., status badge for status groups). */
  icon?: ReactNode;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-alert-group-header-styles';

function ensureAlertGroupHeaderStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-alert-group-header]:hover {
      background: oklch(0.50 0.005 260 / 0.04);
    }
    [data-ts-alert-group-header]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAlertGroupHeaderStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const headerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  height: 36,
  padding: '0 var(--ts-space-3)',
  background: 'var(--ts-panel-header-bg)',
  borderBottom: '1px solid var(--ts-border-subtle)',
  cursor: 'pointer',
  userSelect: 'none',
  transition: 'background 100ms',
  boxSizing: 'border-box',
  fontFamily: 'inherit',
};

const chevronStyle: CSSProperties = {
  flexShrink: 0,
  color: 'var(--ts-text-tertiary)',
  transition: 'transform 150ms ease',
};

const labelStyle: CSSProperties = {
  flex: 1,
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-text-primary)',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const countStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'inherit',
  flexShrink: 0,
  padding: '1px 6px',
  borderRadius: 'var(--ts-radius-sm)',
  background: 'oklch(0.50 0.005 260 / 0.08)',
  lineHeight: 1.4,
};

/* ----- Component --------------------------------------------------------- */

export function AlertGroupHeader({
  label,
  count,
  expanded,
  onExpandedChange,
  icon,
}: AlertGroupHeaderProps): React.JSX.Element {
  const toggle = useCallback(() => {
    onExpandedChange(!expanded);
  }, [expanded, onExpandedChange]);

  const handleKeyDown = useCallback(
    (e: KeyboardEvent<HTMLDivElement>) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        toggle();
      }
    },
    [toggle],
  );

  return (
    <div
      data-ts-alert-group-header=""
      style={headerStyle}
      role="button"
      tabIndex={0}
      aria-expanded={expanded}
      onClick={toggle}
      onKeyDown={handleKeyDown}
    >
      <span style={chevronStyle} aria-hidden="true">
        {expanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
      </span>
      {icon ? <span style={{ flexShrink: 0 }}>{icon}</span> : null}
      <span style={labelStyle}>{label}</span>
      <span style={countStyle} data-testid="group-count">{count}</span>
    </div>
  );
}

AlertGroupHeader.displayName = 'AlertGroupHeader';
