/* -------------------------------------------------------------------------- */
/*  Types                                                                     */
/* -------------------------------------------------------------------------- */

interface Position {
  positionId: string; account: string; symbol: string; assetClass: string;
  baseCurrency: string; quoteCurrency: string; direction: 'Long' | 'Short';
  quantity: number; avgEntryPrice: number; currentPrice: number;
  marketValue: number; costBasis: number; unrealizedPnl: number;
  realizedPnl: number; totalPnl: number; currency: string; fxRate: number;
  lastUpdated: string; trader: string; book: string; status: 'Open' | 'Closed';
  orders?: number;
  exitAvgPrice?: number;
  numTrades?: number;
  winPct?: number;
  duration?: string;
}

interface FilterRule {
  id: string; column: string; operator: string; value: string;
}

/* -------------------------------------------------------------------------- */
/*  Filter logic                                                              */
/* -------------------------------------------------------------------------- */

const TEXT_OPS = [
  { value: 'contains', label: 'contains' },
  { value: 'equals', label: 'equals' },
  { value: 'notEquals', label: 'not equals' },
  { value: 'startsWith', label: 'starts with' },
  { value: 'endsWith', label: 'ends with' },
];
const NUM_OPS = [
  { value: 'eq', label: '=' },
  { value: 'neq', label: '\u2260' },
  { value: 'gt', label: '>' },
  { value: 'lt', label: '<' },
  { value: 'gte', label: '\u2265' },
  { value: 'lte', label: '\u2264' },
];

const NUM_KEYS = new Set([
  'orders', 'quantity', 'avgEntryPrice', 'exitAvgPrice',
  'realizedPnl', 'unrealizedPnl', 'numTrades', 'winPct',
]);

function isNumKey(key: string): boolean { return NUM_KEYS.has(key); }

interface ColAccessor {
  key: string;
  accessor: (row: Position) => string | number | null | undefined;
}

const COL_ACCESSORS: ColAccessor[] = [
  { key: 'symbol', accessor: (r) => r.symbol },
  { key: 'orders', accessor: (r) => r.orders ?? 0 },
  { key: 'quantity', accessor: (r) => r.quantity },
  { key: 'avgEntryPrice', accessor: (r) => r.avgEntryPrice },
  { key: 'exitAvgPrice', accessor: (r) => r.exitAvgPrice ?? r.currentPrice },
  { key: 'realizedPnl', accessor: (r) => r.realizedPnl },
  { key: 'numTrades', accessor: (r) => r.numTrades ?? 0 },
  { key: 'winPct', accessor: (r) => r.winPct ?? null },
  { key: 'duration', accessor: (r) => r.duration ?? '\u2014' },
];

function matchRule(row: Position, rule: FilterRule): boolean {
  if (!rule.value) return true;
  const col = COL_ACCESSORS.find((c) => c.key === rule.column);
  if (!col) return true;
  const raw = col.accessor(row);
  const s = String(raw ?? '').toLowerCase();
  const f = rule.value.toLowerCase();

  if (isNumKey(rule.column) && raw != null) {
    const n = Number(raw), fv = Number(rule.value);
    if (!isNaN(n) && !isNaN(fv)) {
      switch (rule.operator) {
        case 'eq': return n === fv; case 'neq': return n !== fv;
        case 'gt': return n > fv;   case 'lt': return n < fv;
        case 'gte': return n >= fv;  case 'lte': return n <= fv;
      }
    }
  }
  switch (rule.operator) {
    case 'contains': return s.includes(f);
    case 'equals': return s === f;
    case 'notEquals': return s !== f;
    case 'startsWith': return s.startsWith(f);
    case 'endsWith': return s.endsWith(f);
    default: return s.includes(f);
  }
}

let _rid = 0;
function rid(): string { return `r-${++_rid}`; }

