/* -------------------------------------------------------------------------- */
/*  Formatting                                                                */
/* -------------------------------------------------------------------------- */

function fmtNum(v: unknown): string {
  if (v == null) return '\u2014';
  const n = Number(v);
  return isNaN(n) ? String(v) : n.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 6 });
}

/* -------------------------------------------------------------------------- */
/*  Column meta for FilterBuilder                                             */
/* -------------------------------------------------------------------------- */

interface FilterColumnMeta {
  key: string;
  label: string;
  isNum: boolean;
}

const FILTER_COLUMNS: FilterColumnMeta[] = [
  { key: 'symbol', label: 'Symbol', isNum: false },
  { key: 'orders', label: 'Orders', isNum: true },
  { key: 'quantity', label: 'Position', isNum: true },
  { key: 'avgEntryPrice', label: 'Entry Avg', isNum: true },
  { key: 'exitAvgPrice', label: 'Exit Avg', isNum: true },
  { key: 'realizedPnl', label: 'RP&L', isNum: true },
  { key: 'numTrades', label: '# Trades', isNum: true },
  { key: 'winPct', label: 'Win %', isNum: true },
  { key: 'duration', label: 'Duration', isNum: false },
];

