import { useCallback, useMemo, useRef, type CSSProperties } from 'react';
import { Slider } from '../../primitives';
import { NumberInput } from '../../primitives';
import { formatCompactNumber } from '../../financial';

/* -------------------------------------------------------------------------- */
/*  FilterRangeSlider                                                         */
/*  Dual-thumb range slider with min/max inputs and preset buttons.           */
/*  Composes Slider + NumberInput. Uses --ts-screener-filter-* tokens.        */
/* -------------------------------------------------------------------------- */

export interface FilterRangeSliderProps {
  /** Minimum bound of the range. */
  min: number;
  /** Maximum bound of the range. */
  max: number;
  /** Current selected range [low, high]. */
  value: [number, number];
  /** Called when range changes. */
  onValueChange: (value: [number, number]) => void;
  /** Step increment. */
  step?: number;
  /** Format function for displaying values (e.g., formatCompactNumber). */
  formatValue?: (value: number) => string;
  /** Label text displayed above the slider. */
  label?: string;
  /** Preset range buttons. */
  presets?: Array<{ label: string; value: [number, number] }>;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-filter-range-slider-styles';

function ensureFilterRangeSliderStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-filter-range-preset]:hover {
      background: var(--ts-accent-subtle);
      color: var(--ts-accent-default);
      border-color: var(--ts-accent-default);
    }
    [data-ts-filter-range-preset]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureFilterRangeSliderStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-3)',
  width: 240,
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-secondary)',
  fontFamily: 'inherit',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  margin: 0,
};

const inputRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const dashStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  flexShrink: 0,
  fontSize: 'var(--ts-font-sm)',
};

const presetsContainerStyle: CSSProperties = {
  display: 'flex',
  flexWrap: 'wrap',
  gap: 'var(--ts-space-1)',
};

const presetButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  height: 22,
  padding: '0 8px',
  fontSize: 'var(--ts-font-xs)',
  fontFamily: 'inherit',
  color: 'var(--ts-text-secondary)',
  background: 'var(--ts-tag-bg)',
  border: '1px solid var(--ts-tag-border)',
  borderRadius: 'var(--ts-tag-radius, 4px)',
  cursor: 'pointer',
  whiteSpace: 'nowrap',
  boxSizing: 'border-box',
  transition: 'background 150ms, color 150ms, border-color 150ms',
};

const rangeDisplayStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'space-between',
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontVariantNumeric: 'tabular-nums slashed-zero',
  fontFeatureSettings: "'tnum' 1, 'zero' 1",
};

/* ----- Helpers ----------------------------------------------------------- */

function autoDetectStep(min: number, max: number): number {
  const range = max - min;
  if (range <= 1) return 0.0001;
  if (range <= 100) return 0.01;
  if (range <= 1000) return 1;
  if (range <= 1_000_000) return 100;
  if (range <= 1_000_000_000) return 1000;
  return 1_000_000;
}

/* ----- Component --------------------------------------------------------- */

export function FilterRangeSlider({
  min,
  max,
  value,
  onValueChange,
  step,
  formatValue,
  label,
  presets,
}: FilterRangeSliderProps): React.JSX.Element {
  const resolvedStep = step ?? autoDetectStep(min, max);
  const format = formatValue ?? formatCompactNumber;

  /* Keep a ref to current value so callbacks don't depend on `value` —
     this prevents infinite re-render loops with react-aria's NumberInput
     which internally triggers onChange on every render when onChange identity changes. */
  const valueRef = useRef(value);
  valueRef.current = value;

  const onValueChangeRef = useRef(onValueChange);
  onValueChangeRef.current = onValueChange;

  const handleSliderChange = useCallback(
    (sliderValue: number[]) => {
      const low = sliderValue[0];
      const high = sliderValue[1];
      if (low !== undefined && high !== undefined) {
        onValueChangeRef.current([low, high]);
      }
    },
    [],
  );

  const handleMinChange = useCallback(
    (val: number) => {
      const cur = valueRef.current;
      const clamped = Math.max(min, Math.min(val, cur[1]));
      onValueChangeRef.current([clamped, cur[1]]);
    },
    [min],
  );

  const handleMaxChange = useCallback(
    (val: number) => {
      const cur = valueRef.current;
      const clamped = Math.min(max, Math.max(val, cur[0]));
      onValueChangeRef.current([cur[0], clamped]);
    },
    [max],
  );

  const handlePresetClick = useCallback(
    (presetValue: [number, number]) => {
      onValueChangeRef.current([
        Math.max(min, presetValue[0]),
        Math.min(max, presetValue[1]),
      ]);
    },
    [min, max],
  );

  const precision = useMemo(() => {
    if (resolvedStep < 0.001) return 4;
    if (resolvedStep < 0.1) return 2;
    if (resolvedStep < 1) return 1;
    return 0;
  }, [resolvedStep]);

  return (
    <div data-ts-filter-range-slider="" style={containerStyle}>
      {label !== undefined && <div style={labelStyle}>{label}</div>}

      <div style={inputRowStyle}>
        <NumberInput
          value={value[0]}
          onChange={handleMinChange}
          min={min}
          max={value[1]}
          step={resolvedStep}
          precision={precision}
          size="sm"
          label={`${label ?? 'Range'} minimum`}
        />
        <span style={dashStyle} aria-hidden>
          &ndash;
        </span>
        <NumberInput
          value={value[1]}
          onChange={handleMaxChange}
          min={value[0]}
          max={max}
          step={resolvedStep}
          precision={precision}
          size="sm"
          label={`${label ?? 'Range'} maximum`}
        />
      </div>

      <Slider
        value={[value[0], value[1]]}
        onValueChange={handleSliderChange}
        min={min}
        max={max}
        step={resolvedStep}
        label={label ?? 'Range slider'}
      />

      <div style={rangeDisplayStyle}>
        <span>{format(min)}</span>
        <span>{format(max)}</span>
      </div>

      {presets !== undefined && presets.length > 0 && (
        <div style={presetsContainerStyle}>
          {presets.map((preset) => (
            <button
              key={preset.label}
              type="button"
              data-ts-filter-range-preset=""
              style={presetButtonStyle}
              onClick={() => handlePresetClick(preset.value)}
              aria-label={`Set range to ${preset.label}`}
            >
              {preset.label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

FilterRangeSlider.displayName = 'FilterRangeSlider';
