import { forwardRef, type CSSProperties } from 'react';
import { Checkbox as CheckboxPrimitive } from 'radix-ui';
import { Check, Minus } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  Checkbox                                                                  */
/*  Binary or tri-state checkbox with label.                                  */
/*  Wraps Radix Checkbox — uses --ts-checkbox-* tokens.                       */
/* -------------------------------------------------------------------------- */

export interface CheckboxProps {
  /** Checked state: true, false, or 'indeterminate'. */
  checked?: boolean | 'indeterminate';
  /** Called when checked state changes. */
  onCheckedChange?: (checked: boolean | 'indeterminate') => void;
  /** Whether the checkbox is disabled. */
  disabled?: boolean;
  /** Text label rendered beside the checkbox. */
  label?: string;
  /** Alias for setting indeterminate state via a prop. */
  indeterminate?: boolean;
}

/* ----- Style injection for hover/focus states ---------------------------- */

const CHECKBOX_STYLE_ID = 'ts-checkbox-styles';

function ensureCheckboxStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(CHECKBOX_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = CHECKBOX_STYLE_ID;
  sheet.textContent = `
    [data-ts-checkbox]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-checkbox][data-state="checked"],
    [data-ts-checkbox][data-state="indeterminate"] {
      background: var(--ts-checkbox-bg-checked);
      border-color: var(--ts-checkbox-border-checked);
    }
    [data-ts-checkbox]:disabled {
      background: var(--ts-checkbox-bg-disabled);
      border-color: var(--ts-checkbox-border-disabled);
      cursor: not-allowed;
    }
    [data-ts-checkbox-label] {
      cursor: pointer;
      user-select: none;
    }
    [data-ts-checkbox-label][data-disabled] {
      cursor: not-allowed;
      opacity: 0.5;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureCheckboxStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-checkbox-size)',
  height: 'var(--ts-checkbox-size)',
  background: 'var(--ts-checkbox-bg)',
  border: '1px solid var(--ts-checkbox-border)',
  borderRadius: 'var(--ts-checkbox-radius)',
  cursor: 'pointer',
  flexShrink: 0,
  boxSizing: 'border-box',
  transition: 'background 150ms, border-color 150ms',
};

const indicatorStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: 'var(--ts-checkbox-check-color)',
};

const labelWrapperStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const labelTextStyle: CSSProperties = {
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
  color: 'var(--ts-text-primary)',
};

export const Checkbox = forwardRef<HTMLButtonElement, CheckboxProps>(
  function Checkbox(
    { checked, onCheckedChange, disabled = false, label, indeterminate = false },
    ref,
  ) {
    const resolvedChecked = indeterminate ? 'indeterminate' : checked;

    const checkboxElement = (
      <CheckboxPrimitive.Root
        ref={ref}
        data-ts-checkbox=""
        checked={resolvedChecked}
        onCheckedChange={onCheckedChange}
        disabled={disabled}
        style={rootStyle}
      >
        <CheckboxPrimitive.Indicator style={indicatorStyle}>
          {resolvedChecked === 'indeterminate' ? (
            <Minus size={12} aria-hidden />
          ) : (
            <Check size={12} aria-hidden />
          )}
        </CheckboxPrimitive.Indicator>
      </CheckboxPrimitive.Root>
    );

    if (label) {
      return (
        <label
          data-ts-checkbox-label=""
          {...(disabled ? { 'data-disabled': '' } : {})}
          style={labelWrapperStyle}
        >
          {checkboxElement}
          <span style={labelTextStyle}>{label}</span>
        </label>
      );
    }

    return checkboxElement;
  },
);

Checkbox.displayName = 'Checkbox';
