import { forwardRef, type CSSProperties } from 'react';
import { Panel, ScrollArea, Accordion } from '../primitives';
import { Layers } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  DataWindowPanel                                                           */
/*  Panel showing OHLCV and indicator values for the hovered bar.             */
/*  Uses --ts-panel-*, --ts-accordion-*, --ts-data-* tokens.                  */
/* -------------------------------------------------------------------------- */

export interface DataWindowRow {
  /** Row label (e.g., "Open", "High", "Volume"). */
  label: string;
  /** Formatted value string. */
  value: string;
  /** Value direction for coloring: 'up' | 'down' | 'neutral'. */
  direction?: 'up' | 'down' | 'neutral';
}

export interface DataWindowSection {
  /** Section identifier. */
  id: string;
  /** Section header label (e.g., "BTCUSDT - 1D - Binance"). */
  label: string;
  /** Whether the section is expanded. */
  expanded?: boolean;
  /** Key-value data rows. */
  rows: DataWindowRow[];
}

export interface DataWindowPanelProps {
  /** Date header text (e.g., "Thu 12 Mar '26"). */
  dateLabel?: string;
  /** Data sections (one per symbol/indicator). */
  sections: DataWindowSection[];
  /** Called when a section is expanded/collapsed. */
  onSectionToggle?: (sectionId: string) => void;
}

/* ----- Style injection --------------------------------------------------- */

const DATA_WINDOW_STYLE_ID = 'ts-data-window-styles';

function ensureDataWindowStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(DATA_WINDOW_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = DATA_WINDOW_STYLE_ID;
  sheet.textContent = `
    [data-ts-data-window-row]:hover {
      background: var(--ts-data-row-bg-hover);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureDataWindowStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const dateLabelStyle: CSSProperties = {
  padding: `var(--ts-space-2) var(--ts-space-3)`,
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-text-primary)',
  borderBottom: '1px solid var(--ts-panel-border)',
  userSelect: 'none',
};

const rowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  height: 'var(--ts-data-row-height)',
  padding: `0 var(--ts-data-row-padding-x)`,
  fontSize: 'var(--ts-data-cell-font-size)',
  fontFamily: 'var(--ts-data-cell-font)',
  fontVariantNumeric: 'tabular-nums',
};

const rowLabelStyle: CSSProperties = {
  color: 'var(--ts-text-secondary)',
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
};

function getValueColor(direction?: 'up' | 'down' | 'neutral'): string {
  switch (direction) {
    case 'up':
      return 'var(--ts-price-up-text)';
    case 'down':
      return 'var(--ts-price-down-text)';
    default:
      return 'var(--ts-text-primary)';
  }
}

const emptyStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  padding: 'var(--ts-space-6)',
  gap: 'var(--ts-space-2)',
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-sm)',
  textAlign: 'center',
};

export const DataWindowPanel = forwardRef<HTMLDivElement, DataWindowPanelProps>(
  function DataWindowPanel(
    { dateLabel, sections, onSectionToggle },
    ref,
  ) {
    const expandedValues = sections
      .filter((s) => s.expanded !== false)
      .map((s) => s.id);

    if (sections.length === 0) {
      return (
        <Panel ref={ref} title="Data Window">
          <div data-ts-data-window="" style={emptyStyle}>
            <Layers size={24} aria-hidden />
            <span>No data available</span>
            <span style={{ fontSize: 'var(--ts-font-xs)' }}>
              Hover over the chart to see bar values
            </span>
          </div>
        </Panel>
      );
    }

    return (
      <Panel ref={ref} title="Data Window">
        <div data-ts-data-window="">
          <ScrollArea>
            {dateLabel !== undefined && (
              <div style={dateLabelStyle}>{dateLabel}</div>
            )}
            <Accordion
              type="multiple"
              defaultValue={expandedValues}
              onValueChange={(openItems: string[]) => {
                if (onSectionToggle === undefined) return;
                for (const section of sections) {
                  const wasOpen = expandedValues.includes(section.id);
                  const isOpen = openItems.includes(section.id);
                  if (wasOpen !== isOpen) {
                    onSectionToggle(section.id);
                  }
                }
              }}
            >
              {sections.map((section) => (
                <Accordion.Item key={section.id} value={section.id}>
                  <Accordion.Trigger>{section.label}</Accordion.Trigger>
                  <Accordion.Content>
                    {section.rows.map((row) => (
                      <div
                        key={row.label}
                        data-ts-data-window-row=""
                        style={rowStyle}
                      >
                        <span style={rowLabelStyle}>{row.label}</span>
                        <span style={{ color: getValueColor(row.direction), fontVariantNumeric: 'tabular-nums' }}>
                          {row.value}
                        </span>
                      </div>
                    ))}
                  </Accordion.Content>
                </Accordion.Item>
              ))}
            </Accordion>
          </ScrollArea>
        </div>
      </Panel>
    );
  },
);

DataWindowPanel.displayName = 'DataWindowPanel';
