import { forwardRef, type CSSProperties, type ReactNode } from 'react';
import { ChevronUp } from 'lucide-react';
import { Toolbar } from '../../primitives';
import { Tooltip } from '../../primitives';

/* -------------------------------------------------------------------------- */
/*  ConnectionStatusBar                                                       */
/*  32px dock panel showing colored dots per exchange connection.              */
/*  Green = connected, Yellow = degraded, Red = disconnected, Gray = connecting. */
/*  Uses --ts-connection-* tokens.                                            */
/* -------------------------------------------------------------------------- */

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-connection-status-bar-styles';

function ensureConnectionStatusBarStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    @keyframes ts-connection-dot-pulse {
      0%, 100% { opacity: 1; }
      50% { opacity: 0.6; }
    }
    [data-ts-connection-dot][data-status="connected"] [data-ts-dot-indicator] {
      animation: ts-connection-dot-pulse 2s ease-in-out infinite;
    }
    @keyframes ts-connection-dot-spin {
      from { transform: rotate(0deg); }
      to { transform: rotate(360deg); }
    }
    [data-ts-connection-dot][data-status="connecting"] [data-ts-dot-spinner] {
      animation: ts-connection-dot-spin 1s linear infinite;
    }
    [data-ts-connection-status-bar] [data-ts-expand-button]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-connection-dot][data-status="connected"] [data-ts-dot-indicator],
      [data-ts-connection-dot][data-status="connecting"] [data-ts-dot-spinner] {
        animation: none;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureConnectionStatusBarStyles();
}

/* ----- Types ------------------------------------------------------------- */

export type ConnectionStatus = 'connected' | 'disconnected' | 'degraded' | 'connecting';

export interface ExchangeConnectionStatus {
  /** Exchange identifier. */
  id: string;
  /** Display name (e.g., "Binance", "Coinbase"). */
  name: string;
  /** Current connection status. */
  status: ConnectionStatus;
  /** Latency in milliseconds. */
  latencyMs?: number;
  /** Messages received per second. */
  messagesPerSecond?: number;
  /** ISO timestamp of last received message. */
  lastSeen?: string;
  /** Number of subscribed trading pairs. */
  pairsSubscribed?: number;
}

export interface ConnectionStatusBarProps {
  /** Exchange connection statuses. */
  connections: ExchangeConnectionStatus[];
  /** Aggregate messages per second across all connections. */
  totalMessagesPerSecond?: number;
  /** Called when an exchange dot is clicked (e.g., to open config). */
  onConnectionClick?: (connectionId: string) => void;
  /** Called when the expand/config button is clicked. */
  onExpandClick?: () => void;
}

/* ----- Constants --------------------------------------------------------- */

const STATUS_COLORS: Record<ConnectionStatus, string> = {
  connected: 'var(--ts-connection-dot-connected)',
  disconnected: 'var(--ts-connection-dot-disconnected)',
  degraded: 'var(--ts-connection-dot-degraded)',
  connecting: 'var(--ts-connection-dot-connecting)',
};

const STATUS_LABELS: Record<ConnectionStatus, string> = {
  connected: 'Connected',
  disconnected: 'Disconnected',
  degraded: 'Degraded',
  connecting: 'Connecting',
};

/* ----- Styles ------------------------------------------------------------ */

const barInnerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  width: '100%',
  height: 'var(--ts-connection-bar-height)',
  padding: '0 var(--ts-toolbar-padding-x)',
  gap: 'var(--ts-space-2)',
  background: 'var(--ts-connection-bar-bg)',
  borderTop: '1px solid var(--ts-connection-bar-border)',
  boxSizing: 'border-box',
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-connection-bar-text)',
  whiteSpace: 'nowrap',
  lineHeight: 1,
};

const rateStyle: CSSProperties = {
  fontFamily: 'var(--ts-connection-bar-rate-font)',
  fontSize: 'var(--ts-connection-bar-rate-font-size)',
  color: 'var(--ts-connection-bar-text)',
  whiteSpace: 'nowrap',
  lineHeight: 1,
};

const dotsContainerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-connection-dot-gap)',
  flex: 1,
  justifyContent: 'flex-end',
};

const dotButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
  padding: '2px',
  borderRadius: 'var(--ts-radius-full)',
  boxSizing: 'border-box',
};

const dotIndicatorStyle: CSSProperties = {
  width: 'var(--ts-connection-dot-size)',
  height: 'var(--ts-connection-dot-size)',
  borderRadius: 'var(--ts-radius-full)',
};

const spinnerStyle: CSSProperties = {
  width: 'var(--ts-connection-dot-size)',
  height: 'var(--ts-connection-dot-size)',
  borderRadius: 'var(--ts-radius-full)',
  border: '1.5px solid transparent',
  borderTopColor: 'var(--ts-connection-dot-connecting)',
  boxSizing: 'border-box',
};

const expandButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-icon-button-size-sm)',
  height: 'var(--ts-icon-button-size-sm)',
  borderRadius: 'var(--ts-button-radius)',
  background: 'transparent',
  color: 'var(--ts-text-secondary)',
  cursor: 'pointer',
  transition: 'background 100ms, color 100ms',
  flexShrink: 0,
  boxSizing: 'border-box',
};

/* ----- Helpers ----------------------------------------------------------- */

function formatMessageRate(rate: number): string {
  if (rate >= 1000) {
    return `${(rate / 1000).toFixed(1)}k msg/s`;
  }
  return `${Math.round(rate).toLocaleString()} msg/s`;
}

function buildTooltipContent(conn: ExchangeConnectionStatus): ReactNode {
  const lines: string[] = [
    `${conn.name}: ${STATUS_LABELS[conn.status]}`,
  ];
  if (conn.latencyMs !== undefined) {
    lines.push(`Latency: ${conn.latencyMs}ms`);
  }
  if (conn.messagesPerSecond !== undefined) {
    lines.push(`Messages: ${conn.messagesPerSecond}/s`);
  }
  if (conn.lastSeen !== undefined) {
    lines.push(`Last seen: ${conn.lastSeen}`);
  }
  if (conn.pairsSubscribed !== undefined) {
    lines.push(`Pairs: ${conn.pairsSubscribed}`);
  }
  return lines.join('\n');
}

/* ----- Component --------------------------------------------------------- */

export const ConnectionStatusBar = forwardRef<HTMLDivElement, ConnectionStatusBarProps>(
  function ConnectionStatusBar(
    { connections, totalMessagesPerSecond, onConnectionClick, onExpandClick },
    ref,
  ) {
    return (
      <div ref={ref} data-ts-connection-status-bar="" style={{ display: 'contents' }}>
        <Toolbar>
          <div style={barInnerStyle}>
            <span style={labelStyle}>Feeds</span>
            {totalMessagesPerSecond !== undefined ? (
              <span style={rateStyle}>
                {formatMessageRate(totalMessagesPerSecond)}
              </span>
            ) : null}
            <div style={dotsContainerStyle}>
              {connections.map((conn) => (
                <Tooltip
                  key={conn.id}
                  content={buildTooltipContent(conn)}
                  side="top"
                  delayDuration={200}
                >
                  <button
                    type="button"
                    data-ts-connection-dot=""
                    data-status={conn.status}
                    aria-label={`${conn.name}: ${STATUS_LABELS[conn.status]}`}
                    style={dotButtonStyle}
                    onClick={() => onConnectionClick?.(conn.id)}
                  >
                    {conn.status === 'connecting' ? (
                      <span data-ts-dot-spinner="" style={spinnerStyle} />
                    ) : (
                      <span
                        data-ts-dot-indicator=""
                        style={{
                          ...dotIndicatorStyle,
                          background: STATUS_COLORS[conn.status],
                        }}
                      />
                    )}
                  </button>
                </Tooltip>
              ))}
            </div>
            {onExpandClick !== undefined ? (
              <button
                type="button"
                data-ts-expand-button=""
                aria-label="Expand feeds configuration"
                style={expandButtonStyle}
                onClick={onExpandClick}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = 'var(--ts-button-ghost-bg-hover)';
                  e.currentTarget.style.color = 'var(--ts-text-primary)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = 'transparent';
                  e.currentTarget.style.color = 'var(--ts-text-secondary)';
                }}
              >
                <ChevronUp size={14} />
              </button>
            ) : null}
          </div>
        </Toolbar>
      </div>
    );
  },
);

ConnectionStatusBar.displayName = 'ConnectionStatusBar';
